import{_ as n,o as e,c as t,S as s}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"AI Agent（智能体）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_24-agent.md","filePath":"直击概念/17ai/s_ai_24-agent.md","lastUpdated":1778207238000}'),i={name:"直击概念/17ai/s_ai_24-agent.md"};function l(r,a,o,p,g,h){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="ai-agent-智能体" tabindex="-1">AI Agent（智能体） <a class="header-anchor" href="#ai-agent-智能体" aria-label="Permalink to &quot;AI Agent（智能体）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>AI Agent（智能体）是能够<strong>自主规划、使用工具、执行多步任务</strong>的 AI 系统。与传统 LLM 应用的区别在于：Agent 不只是&quot;回答&quot;，而是能<strong>采取行动</strong>——调用 API、搜索信息、读写文件、执行代码等。</p><p>简单类比：LLM 是大脑，Agent 是有了手和工具的大脑。</p><h2 id="agent-的核心能力" tabindex="-1">Agent 的核心能力 <a class="header-anchor" href="#agent-的核心能力" aria-label="Permalink to &quot;Agent 的核心能力&quot;">​</a></h2><h3 id="规划-planning" tabindex="-1">规划（Planning） <a class="header-anchor" href="#规划-planning" aria-label="Permalink to &quot;规划（Planning）&quot;">​</a></h3><p>将复杂任务拆解为可执行的子步骤：</p><ul><li><strong>任务分解</strong>：把&quot;帮我分析这份数据并生成报告&quot;分解为：读取数据 → 清洗 → 分析 → 生成图表 → 写报告</li><li><strong>动态调整</strong>：根据执行结果实时调整计划</li></ul><h3 id="工具使用-tool-use-function-calling" tabindex="-1">工具使用（Tool Use / Function Calling） <a class="header-anchor" href="#工具使用-tool-use-function-calling" aria-label="Permalink to &quot;工具使用（Tool Use / Function Calling）&quot;">​</a></h3><p>Agent 可以调用外部工具来扩展能力：</p><ul><li>搜索引擎（获取最新信息）</li><li>计算器（精确计算）</li><li>代码执行器（运行代码）</li><li>API 调用（操作外部系统）</li></ul><p>详见 Function Calling 章节。</p><h3 id="记忆-memory" tabindex="-1">记忆（Memory） <a class="header-anchor" href="#记忆-memory" aria-label="Permalink to &quot;记忆（Memory）&quot;">​</a></h3><ul><li><strong>短期记忆</strong>：当前对话的上下文</li><li><strong>长期记忆</strong>：跨会话的知识积累（向量库 + RAG）</li><li><strong>工作记忆</strong>：当前任务中间结果</li></ul><h2 id="react-模式" tabindex="-1">ReAct 模式 <a class="header-anchor" href="#react-模式" aria-label="Permalink to &quot;ReAct 模式&quot;">​</a></h2><p>最经典的 Agent 推理-行动框架：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>循环：</span></span>
<span class="line"><span>  Thought（思考）：我当前需要做什么？</span></span>
<span class="line"><span>  Action（行动）：调用工具 / 执行操作</span></span>
<span class="line"><span>  Observation（观察）：工具返回了什么结果？</span></span>
<span class="line"><span>  (重复直到任务完成)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户：今天北京天气如何？适合户外跑步吗？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Thought：我需要查询北京今天的天气</span></span>
<span class="line"><span>Action：调用 weather_api(city=&quot;北京&quot;)</span></span>
<span class="line"><span>Observation：晴，15°C，PM2.5=35</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Thought：天气晴好，温度适宜，空气质量良好</span></span>
<span class="line"><span>Answer：今天北京天气晴好，气温15°C，空气质量优，非常适合户外跑步！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="agent-类型" tabindex="-1">Agent 类型 <a class="header-anchor" href="#agent-类型" aria-label="Permalink to &quot;Agent 类型&quot;">​</a></h2><table><thead><tr><th>类型</th><th>描述</th><th>应用</th></tr></thead><tbody><tr><td>单 Agent</td><td>一个模型完成所有操作</td><td>个人助手</td></tr><tr><td>Multi-Agent</td><td>多个 Agent 分工协作</td><td>复杂系统（详见 Multi-Agent 章节）</td></tr><tr><td>RAG Agent</td><td>主要依赖检索增强生成</td><td>知识问答</td></tr><tr><td>Code Agent</td><td>专注于代码执行和生成</td><td>编程助手</td></tr></tbody></table><h2 id="前端-agent-场景" tabindex="-1">前端 Agent 场景 <a class="header-anchor" href="#前端-agent-场景" aria-label="Permalink to &quot;前端 Agent 场景&quot;">​</a></h2><ul><li><strong>客服 Agent</strong>：查询订单 + 知识库回答 + 操作工单系统</li><li><strong>数据分析 Agent</strong>：用户问 → Agent 写 SQL → 执行 → 可视化结果</li><li><strong>开发助手 Agent</strong>：从需求描述到生成代码文件</li><li><strong>办公 Agent</strong>：读取邮件 → 提取信息 → 更新日程 → 回复确认</li></ul><h2 id="agent-的核心挑战" tabindex="-1">Agent 的核心挑战 <a class="header-anchor" href="#agent-的核心挑战" aria-label="Permalink to &quot;Agent 的核心挑战&quot;">​</a></h2><ul><li><strong>可靠性</strong>：多步任务中任何一步出错都可能失败</li><li><strong>成本</strong>：一次 Agent 调用可能涉及 10+ 次 LLM API 调用</li><li><strong>安全</strong>：Agent 执行不可控操作的风险（如意外删除文件）</li><li><strong>循环</strong>：Agent 可能陷入无效循环</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>AI Agent 和传统 LLM 应用的核心区别是什么？</li><li>描述 ReAct 模式的工作循环。</li><li>你在前端实现过 Agent 吗？遇到了什么挑战？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">ReAct: Synergizing Reasoning and Acting in Language Models</a></li><li><a href="https://langchain-ai.github.io/langgraph/" target="_blank" rel="noreferrer">LangGraph Agent Guide</a></li><li><a href="https://www.anthropic.com/research/building-effective-agents" target="_blank" rel="noreferrer">Building effective agents - Anthropic</a></li></ul>`,29)])])}const u=n(i,[["render",l]]);export{c as __pageData,u as default};
